import{_ as a,o as i,c as t,ag as l}from"./chunks/framework.CN92kLqn.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),o={name:"changelog.md"};function r(n,e,c,d,s,u){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="_1-1-0" tabindex="-1">1.1.0 <a class="header-anchor" href="#_1-1-0" aria-label="Permalink to &quot;1.1.0&quot;">​</a></h2><h3 id="sqlite-database-provider" tabindex="-1">SQLite Database Provider <a class="header-anchor" href="#sqlite-database-provider" aria-label="Permalink to &quot;SQLite Database Provider&quot;">​</a></h3><ul><li>Added SQLite as the <strong>default</strong> database backend — zero external dependencies</li><li>Full multi-tenant support with per-tenant <code>.sqlite</code> files</li><li>All 16 domain mixins implemented (tenants, users, projects, models, vectors, tracing, guardrails, RAG, memory, alerts, prompts, quotas, files, providers, inference, API tokens)</li><li>WAL mode and foreign keys enabled for performance and data integrity</li><li>Switch to MongoDB with <code>DB_PROVIDER=mongodb</code></li></ul><h3 id="sqlite-vector-provider" tabindex="-1">SQLite Vector Provider <a class="header-anchor" href="#sqlite-vector-provider" aria-label="Permalink to &quot;SQLite Vector Provider&quot;">​</a></h3><ul><li>Added <code>sqlite-vector</code> provider contract for local vector storage</li><li>Brute-force cosine, dot-product, and euclidean similarity search</li><li>No external vector database required</li><li>Batch upsert within transactions for data consistency</li></ul><h3 id="local-file-provider" tabindex="-1">Local File Provider <a class="header-anchor" href="#local-file-provider" aria-label="Permalink to &quot;Local File Provider&quot;">​</a></h3><ul><li>Already available as <code>local-file</code> provider</li></ul><h3 id="quick-installation" tabindex="-1">Quick Installation <a class="header-anchor" href="#quick-installation" aria-label="Permalink to &quot;Quick Installation&quot;">​</a></h3><ul><li>Zero-dependency setup: just <code>npm install &amp;&amp; npm run dev</code></li><li>Docker runs with a single volume mount for persistence</li><li>Updated documentation with Quick Installation section</li></ul><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><ul><li>New env vars: <code>DB_PROVIDER</code> (default: <code>sqlite</code>), <code>SQLITE_DATA_DIR</code> (default: <code>./data</code>)</li><li><code>MONGODB_URI</code> now only required when <code>DB_PROVIDER=mongodb</code></li></ul><hr><h2 id="_1-0-0" tabindex="-1">1.0.0 <a class="header-anchor" href="#_1-0-0" aria-label="Permalink to &quot;1.0.0&quot;">​</a></h2><p>Initial release of the Cognipeer Gateway documentation.</p><h3 id="core-infrastructure" tabindex="-1">Core Infrastructure <a class="header-anchor" href="#core-infrastructure" aria-label="Permalink to &quot;Core Infrastructure&quot;">​</a></h3><ul><li>Centralized configuration via <code>getConfig()</code></li><li>Winston structured logging with request context</li><li>AsyncLocalStorage-based request context propagation</li><li>Provider-based cache (none / memory / Redis)</li><li>Retry with exponential backoff + circuit breaker</li><li>LRU runtime pool for provider SDK instances</li><li>Fire-and-forget async task runner</li><li>Health check registry</li><li>Graceful lifecycle management</li><li>Configurable CORS for client APIs</li></ul><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ul><li>Multi-tenant architecture with per-tenant databases</li><li>JWT session + API token authentication</li><li>Contract-driven provider system (LLM, Vector, File)</li><li>OpenAI-compatible chat completions and embeddings</li><li>Vector store management (multi-provider)</li><li>Agent tracing (batch + streaming)</li><li>Guardrails (PII, moderation, prompt shield, custom)</li><li>RAG pipeline (ingest, chunk, embed, query)</li><li>Versioned prompt templates with environment deployment</li><li>Semantic memory stores</li><li>File storage with Markdown conversion</li><li>License-based feature control</li><li>Quota and rate limiting</li></ul><h3 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h3><ul><li>Docker multi-stage build</li><li>Kubernetes Helm chart</li><li>GitHub Pages documentation</li></ul>',21)])])}const p=a(o,[["render",r]]);export{m as __pageData,p as default};
